export const HEADLESS_RUNTIME_SCHEMA_VERSION = 1;
export const HEADLESS_RUNTIME_EVENT_TYPES = new Set([
    "message.updated",
    "message.removed",
    "message.part.updated",
    "message.part.delta",
    "message.part.removed",
    "permission.asked",
    "permission.replied",
    "question.asked",
    "question.replied",
    "question.rejected",
    "todo.updated",
    "session.diff",
    "session.goal",
    "session.deleted",
    "session.created",
    "session.updated",
    "session.status",
    "session.error",
    "task.queue.created",
    "task.queue.updated",
    "task.queue.deleted",
    "scheduled.task.created",
    "scheduled.task.updated",
    "scheduled.task.deleted",
    "mcp.tools.changed",
    "lsp.updated",
    "code.index.progress",
    "code.index.state",
    "vcs.branch.updated",
    "workflow.run.created",
    "workflow.run.updated",
    "workflow.run.started",
    "workflow.run.blocked",
    "workflow.run.paused",
    "workflow.run.resumed",
    "workflow.run.completed",
    "workflow.run.failed",
    "workflow.run.cancelled",
    "workflow.phase.updated",
    "workflow.phase.started",
    "workflow.phase.completed",
    "workflow.phase.failed",
    "workflow.child.created",
    "workflow.child.updated",
    "workflow.child.started",
    "workflow.child.completed",
    "workflow.child.failed",
    "workflow.child.cancelled",
    "workflow.artifact.written",
    "workflow.budget.appended",
    "workflow.budget.warning",
    "workflow.budget.exceeded",
    "workflow.verification.attached",
    "server.connected",
    "server.heartbeat",
    "server.instance.disposed",
]);
export function isHeadlessRuntimeEvent(event) {
    if (!event || typeof event !== "object")
        return false;
    if (!("type" in event))
        return false;
    const value = event.type;
    return typeof value === "string" && HEADLESS_RUNTIME_EVENT_TYPES.has(value);
}
